3261 Instruction *InstCombinerImpl::visitBranchInst(BranchInst &BI) {
3262   if (BI.isUnconditional())
3263     return visitUnconditionalBranchInst(BI);
3264 
3265   // Change br (not X), label True, label False to: br X, label False, True
3266   Value *Cond = BI.getCondition();
3267   Value *X;
3268   if (match(Cond, m_Not(m_Value(X))) && !isa<Constant>(X)) {
3269     // Swap Destinations and condition...
3270     BI.swapSuccessors();
3271     return replaceOperand(BI, 0, X);
3272   }
3273 
3274   // Canonicalize logical-and-with-invert as logical-or-with-invert.
3275   // This is done by inverting the condition and swapping successors:
3276   // br (X && !Y), T, F --> br !(X && !Y), F, T --> br (!X || Y), F, T
3277   Value *Y;
3278   if (isa<SelectInst>(Cond) &&
3279       match(Cond,
3280             m_OneUse(m_LogicalAnd(m_Value(X), m_OneUse(m_Not(m_Value(Y))))))) {
3281     Value *NotX = Builder.CreateNot(X, "not." + X->getName());
3282     Value *Or = Builder.CreateLogicalOr(NotX, Y);
3283     BI.swapSuccessors();
3284     return replaceOperand(BI, 0, Or);
3285   }
3286 
3287   // If the condition is irrelevant, remove the use so that other
3288   // transforms on the condition become more effective.
3289   if (!isa<ConstantInt>(Cond) && BI.getSuccessor(0) == BI.getSuccessor(1))
3290     return replaceOperand(BI, 0, ConstantInt::getFalse(Cond->getType()));
3291 
3292   // Canonicalize, for example, fcmp_one -> fcmp_oeq.
3293   CmpInst::Predicate Pred;
3294   if (match(Cond, m_OneUse(m_FCmp(Pred, m_Value(), m_Value()))) &&
3295       !isCanonicalPredicate(Pred)) {
3296     // Swap destinations and condition.
3297     auto *Cmp = cast<CmpInst>(Cond);
3298     Cmp->setPredicate(CmpInst::getInversePredicate(Pred));
3299     BI.swapSuccessors();
3300     Worklist.push(Cmp);
3301     return &BI;
3302   }
3303 
3304   if (isa<UndefValue>(Cond)) {
3305     handlePotentiallyDeadSuccessors(BI.getParent(), /*LiveSucc*/ nullptr);
3306     return nullptr;
3307   }
3308   if (auto *CI = dyn_cast<ConstantInt>(Cond)) {
3309     handlePotentiallyDeadSuccessors(BI.getParent(),
3310                                     BI.getSuccessor(!CI->getZExtValue()));
3311     return nullptr;
3312   }
3313 
3314   DC.registerBranch(&BI);
3315   return nullptr;
3316 }
